def gen(rng, size):
    import string
    n = max(1, min(size, 50))
    length = rng.randint(1, 8)
    def random_word(ln):
        return ''.join(rng.choice(string.ascii_lowercase) for _ in range(ln))
    pattern = random_word(length)
    words = []
    for _ in range(n):
        if rng.random() < 0.3:
            letters = list(string.ascii_lowercase)
            rng.shuffle(letters)
            mapping = {}
            out = []
            for c in pattern:
                if c not in mapping:
                    mapping[c] = letters[len(mapping)]
                out.append(mapping[c])
            w = ''.join(out)
        else:
            w = random_word(length)
        words.append(w)
    return [words, pattern]

