class Solution:
    def findAndReplacePattern(self, words, pattern):
        def encode(s):
            mapping = {}
            result = []
            for c in s:
                if c not in mapping:
                    mapping[c] = len(mapping)
                result.append(mapping[c])
            return tuple(result)
        pat_enc = encode(pattern)
        return [w for w in words if encode(w) == pat_enc]

