var findAndReplacePattern = function(words, pattern) {
    function encode(s) {
        const map = new Map();
        const res = [];
        for (const c of s) {
            if (!map.has(c)) map.set(c, map.size);
            res.push(map.get(c));
        }
        return res.join(',');
    }
    const patEnc = encode(pattern);
    return words.filter(w => encode(w) === patEnc);
};
